:root {
  /* ==========================================
     全局基础设定：底栏、输入框
     ========================================== */
  /* 底栏背景颜色 */
  --input-area-bg: #F1F1F1;

  /* 输入框背景白色、去掉边框、方圆 */
  --input-box-bg: #FFFFFF;
  --input-box-border: none;
  --input-box-radius: 10px; 
}

/* ==========================================
   清空原有的胶囊限制，腾出两排的空间
   ========================================== */
.input-area-custom {
  padding: 0 !important;
}
.input-row-wrapper {
  position: relative !important;
  display: block !important;
  min-height: 110px !important; 
}
.input-btns-right {
  position: static !important;
}

/* 强制隐藏输入框的占位符 */
.input-box-custom::placeholder {
  color: transparent !important;
  -webkit-text-fill-color: transparent !important;
}

/* ==========================================
   第一排：纯白方圆输入框 + AI按钮
   ========================================== */
.input-action-bar-custom {
  position: absolute !important;
  background-color: #FFFFFF !important;
  border-radius: 12px !important;   
  border: none !important;
  box-shadow: none !important;
  overflow: visible !important;     

  left: 15px !important; 
  top: 10px !important;
  width: 78% !important; 
  height: 42px !important; 

  padding: 0 !important;
  margin: 0 !important;
}

.input-box-custom {
  position: absolute !important;
  left: 0 !important;
  top: 0 !important;
  width: 100% !important;
  height: 100% !important;
  background: transparent !important; 
  border: none !important;
  box-shadow: none !important;
  padding: 10px 15px !important;
  box-sizing: border-box !important;
}

/* 💥 强行杀掉自带图标 💥 */
.input-btn-ai *, .send-btn-custom *, .input-btn-plus *, .input-btn-mic *, .input-btn-sticker * {
  display: none !important;
}

/* ==========================================
   1. AI 按钮 (右侧) —— 遮罩染色魔法
   ========================================== */
.input-btn-ai, .send-btn-custom {
  position: absolute !important;
  width: 40px !important;   
  height: 40px !important;
  background: transparent !important; 
  overflow: visible !important; 

  right: -54px !important;  
  top: 1px !important;      
}

.input-btn-ai::after, .send-btn-custom::after {
  content: "";
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%); 

  /* 💥 使用 Mask 技术强行给图片染上 FDEBF0 颜色 💥 */
  background-color: #FDEBF0 !important; 
  -webkit-mask-image: url('https://img.heliar.top/file/1779100630944_retouch_2026051817072255.png');
  -webkit-mask-size: contain;
  -webkit-mask-position: center;
  -webkit-mask-repeat: no-repeat;
  background-image: none !important;

  width: 60px; 
  height: 35px;
}

/* ==========================================
   2. 加号按钮 (左下角)
   ========================================== */
.input-btn-plus {
  position: absolute !important;
  margin: 0 !important;
  width: 40px !important;
  height: 40px !important;
  background: transparent !important;
  overflow: visible !important;

  left: 17px !important;    
  top: 61px !important;     
}

.input-btn-plus::after {
  content: "";
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  background-image: url('https://img.heliar.top/file/1779099675757_retouch_2026051817012903.png');
  background-position: center;
  background-repeat: no-repeat;
  background-size: contain;

  width: 23px;
  height: 23px;
}

/* ==========================================
   3. 装饰贴图（它本来就没点击区，不用分离）
   ========================================== */
.input-row-wrapper::before {
  content: "";
  position: absolute;
  background: url('https://img.heliar.top/file/1779099679511_retouch_2026051817052301.png') no-repeat center/contain;
  pointer-events: none;
  z-index: 10;

  left: 90px;   
  top: 38px;    
  width: 160px;  
  height: 90px;
}

/* ==========================================
   4. 语音按钮
   ========================================== */
.input-btn-mic {
  position: absolute !important;
  margin: 0 !important;
  width: 40px !important;
  height: 40px !important;
  background: transparent !important;
  overflow: visible !important;

  left: 275px !important;   
  top: 54px !important;    
}

.input-btn-mic::after {
  content: "";
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  background-image: url('https://img.heliar.top/file/1779099549238_retouch_2026051817063690.png');
  background-position: center;
  background-repeat: no-repeat;
  background-size: contain;

  width: 23px;
  height: 23px;
}

/* ==========================================
   5. 表情按钮
   ========================================== */
.input-btn-sticker {
  position: absolute !important;
  margin: 0 !important;
  width: 40px !important;
  height: 40px !important;
  background: transparent !important;
  overflow: visible !important;

  left: 340px !important;  
  top: 54px !important;    
}

.input-btn-sticker::after {
  content: "";
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  background-image: url('https://img.heliar.top/file/1779099554667_retouch_2026051817070027.png');
  background-position: center;
  background-repeat: no-repeat;
  background-size: contain;

  width: 23px;
  height: 23px;
}

/* ==========================================
   6. 气泡颜色与形状 (方圆角)
   ========================================== */
:root {
  /* 我方气泡：FDEBF0 (超浅粉色) */
  --bubble-me-bg: #FDEBF0;
  --bubble-me-color: #262626;     /* 改成深色字，不然白色字看不见 */
  --bubble-me-radius: 12px;       
  --bubble-me-radius-first: 12px;
  --bubble-me-radius-mid: 12px;
  --bubble-me-radius-last: 12px;

  /* 对方气泡：白色 */
  --bubble-them-bg: #FFFFFF;
  --bubble-them-color: #262626;   
  --bubble-them-radius: 12px;
  --bubble-them-radius-first: 12px;
  --bubble-them-radius-mid: 12px;
  --bubble-them-radius-last: 12px;

  /* 缩小字体与间距 */
  --bubble-me-font-size: 13px;
  --bubble-them-font-size: 13px;
  --bubble-me-padding: 7px 12px;
  --bubble-them-padding: 7px 12px;
  --avatar-size: 32px;
  --plain-avatar-size: 32px;
  --avatar-margin: 5px;
  --plain-avatar-gap: 5px;
  --chat-messages-gap: 2px;
  --plain-gap-within-group: 2px;
  --plain-gap-between-groups: 10px;

  /* 转账气泡颜色适配 */
  --transfer-card-bg: #0099FF;
  --transfer-card-border: none;

  /* 我方转账变成粉色+深色字适配 */
  --transfer-me-card-bg: #FDEBF0;
  --transfer-me-amount-color: #262626;
  --transfer-me-label-color: rgba(0, 0, 0, 0.6);
  --transfer-me-subtitle-color: rgba(0, 0, 0, 0.5);
  --transfer-me-status-color: rgba(0, 0, 0, 0.6);
  --transfer-me-divider-color: rgba(0, 0, 0, 0.1);
  --transfer-me-icon-bg: rgba(0, 0, 0, 0.05);

  --transfer-them-card-bg: #0099FF;
  --transfer-them-amount-color: #FFFFFF;
  --transfer-them-label-color: rgba(255, 255, 255, 0.9);
  --transfer-them-subtitle-color: rgba(255, 255, 255, 0.7);
  --transfer-them-status-color: rgba(255, 255, 255, 0.9);
  --transfer-them-divider-color: rgba(255, 255, 255, 0.2);
  --transfer-them-icon-bg: rgba(255, 255, 255, 0.25);

  /* 强制取消阴影和边框 */
  --bubble-me-shadow: none;
  --bubble-them-shadow: none;
  --bubble-them-border: none;
}

.bubble-me-custom,
.bubble-them-custom {
  box-shadow: none !important;
  border: none !important;
}

/* ==========================================
   7. 强制降低转账气泡高度
   ========================================== */
.msg-transfer-card {
  padding: 2px 14px !important; /* padding 不允许负数，已修正为最小合法极限 */ 
  min-height: 0 !important; 
}

.msg-transfer-amount {
  font-size: 16px !important; 
  line-height: 1.2 !important;
}

.msg-transfer-card hr, 
.msg-transfer-divider {
  margin: -2px 0 !important; 
}

/* ==========================================
   8. 顶栏样式设置
   ========================================== */
:root {
  --chat-header-bg: #F1F1F1;
  --chat-header-title-color: #CF9B48;
  --chat-header-title-size: 16px; 

  --info-btn-icon: url('https://img.heliar.top/file/1779095667747_retouch_2026051817092494.png');
  --btn-info-scale: 0.8; 
  --btn-info-translate-x: 0px;  
  --btn-info-translate-y: 1px;  
}

.header-avatar-container {
  display: none !important;
}

.header-btn-phone, 
.header-btn-video {
  opacity: 0 !important;
}

.chat-header-title {
  position: relative !important; 
  overflow: visible !important; 
  transform: translate(0px, -5px) !important;
}

.chat-header-title::before {
  content: "";
  position: absolute;
  background: url('https://img.heliar.top/file/1779095674833_retouch_2026051817121030.png') no-repeat left center/contain;
  pointer-events: none; 
  width: 80px;  
  height: 15px; 
  left: 0px;      
  bottom: -10px;  
}

.chat-header-title::after {
  content: "";
  position: absolute;
  background: url('https://img.heliar.top/file/1779095667209_retouch_2026051817082930.png') no-repeat center/contain;
  pointer-events: none;
  width: 80px; 
  height: 22px; 
  right: -90px;   
  top: -2px;      
}
/* ==========================================
   在 AI/发送 按钮的粉色贴图正中心写上白色“发送”
   ========================================== */
.input-btn-ai::before, .send-btn-custom::before {
  content: "发送" !important;
  position: absolute;
  top: 50%; 
  left: 50%;
  transform: translate(-50%, -50%); 

  color: #FFFFFF !important;      /* 纯白文字 */
  font-size: 12px !important;     /* 字体大小（根据贴图大小调整） */
  font-weight: bold !important;   /* 字体加粗 */
  letter-spacing: 1px !important; /* 微微拉开一点字间距更好看 */
  margin-left: 1px !important;    /* 修正间距带来的轻微偏移，保证绝对居中 */

  z-index: 10 !important;         /* 强制浮在粉色贴图的上方 */
  pointer-events: none !important;/* 保证文字不会阻挡手指的点击 */
  white-space: nowrap !important; /* 防止文字换行 */
}

