.msg-reply-offset-me .msg-reply-offset-bubble::after {
    content: "";
    position: absolute;
    left: 18px;
    bottom: -40px;
    width: 30px;
    height: 30px;
    background: none;
    border-left: 3px solid #e9e9e9;
    border-bottom: 3px solid #e9e9e9;
