/* ================================================
 * 仿微信 日夜自动切换版 v1.0
 * 基于 data-time-of-day 属性自动切换日/夜间模式
 *   morning + day   → 日间模式
 *   evening + night → 夜间模式
 * 
 * 结构基于 2.0 夜间版（更稳定），功能合并 4.0 全部特性
 * 已修复 4.0 所有已知 bug
 * ⚠️ 请清空整个 CSS 文件再粘贴
 * ================================================ */

/* ================================================
 * 可调变量区
 * ================================================ */
:root {
    --wx-input-width: 238px;
    --wx-edge-padding: -2px;
    --wx-time-gap: 16px;
    --ios-mode: 0;
    --translation-always-show: 0;
    /* ── 金额位置微调区（6张卡片独立调整） ── */
    /* 我方 · 待接收 */
    --tc-me-pending-left: 66px;
    --tc-me-pending-top: 14px;
    /* 我方 · 已接收 */
    --tc-me-accepted-left: 62px;
    --tc-me-accepted-top: 15px;
    /* 我方 · 已退还 */
    --tc-me-refunded-left: 62px;
    --tc-me-refunded-top: 15px;
    /* 对方 · 待收款 */
    --tc-them-pending-left: 70px;
    --tc-them-pending-top: 15px;
    /* 对方 · 已接收 */
    --tc-them-accepted-left: 68px;
    --tc-them-accepted-top: 15px;
    /* 对方 · 已退还 */
    --tc-them-refunded-left: 68px;
    --tc-them-refunded-top: 15px;

}

/* ================================================
 * 🎨 日/夜间主题色变量
 * :root 里放日间色做兜底（属性未注入时也正常显示）
 * ================================================ */
:root {
    --wx-bg: #ededed;
    --wx-header-border: #d5d5d5;
    --wx-title-color: #000;
    --wx-dots-color: #000;
    --wx-icon-invert: none;
    --wx-timestamp-color: #a5a5a5;
    --wx-bubble-them-bg: #ffffff;
    --wx-bubble-them-color: #000;
    --wx-bubble-me-bg: #95ec69;
    --wx-bubble-me-color: #000;
    --wx-input-bg: #f7f7f7;
    --wx-input-border: #d5d5d5;
    --wx-input-box-bg: #ffffff;
    --wx-input-text: #000;
    --wx-status-color: #a5a5a5;
    --wx-quote-bg: #E3E3E3;
    --wx-quote-color: #8a8a8a;
    --wx-transfer-bg: #f5af3c;
    --wx-more-bg: #f7f7f7;
    --wx-more-border: #d5d5d5;
    --wx-more-text: #000;
    --wx-more-shadow: rgba(0,0,0,0.15);
    --wx-scrollbar: rgba(0,0,0,0.15);
    --wx-selection-bg: rgba(7,193,96,0.25);
    --wx-selection-color: #000;
    --wx-translation-hint: #b2b2b2;
}
/* 🌙 夜间模式 — 跟随本机时间自动切换 */
[data-time-of-day="evening"],
[data-time-of-day="night"] {
    --wx-bg: #1a1a1a;
    --wx-header-border: #2a2a2a;
    --wx-title-color: #ffffff;
    --wx-dots-color: #ffffff;
    --wx-icon-invert: brightness(0) invert(1);
    --wx-timestamp-color: #777;
    --wx-bubble-them-bg: #2c2c2c;
    --wx-bubble-them-color: #e5e5e5;
    --wx-bubble-me-bg: #07C160;
    --wx-bubble-me-color: #000;
    --wx-input-bg: #262626;
    --wx-input-border: #333;
    --wx-input-box-bg: #3a3a3a;
    --wx-input-text: #e5e5e5;
    --wx-status-color: #777;
    --wx-quote-bg: #383838;
    --wx-quote-color: #9a9a9a;
    --wx-transfer-bg: #c87f1e;
    --wx-more-bg: #2c2c2c;
    --wx-more-border: #3a3a3a;
    --wx-more-text: #e5e5e5;
    --wx-more-shadow: rgba(0,0,0,0.3);
    --wx-scrollbar: rgba(255,255,255,0.15);
    --wx-selection-bg: rgba(7,193,96,0.35);
    --wx-selection-color: #fff;
    --wx-translation-hint: #666;
}


/* ================================================
