/* ================================================
 * 转账卡：图层套壳完整版（金额左对齐 · 长度变化往右延伸）
 * ================================================ */

/* 🎛️ 可调变量区 */
.msg-transfer-card {
    --tc-width: 260px;
    --tc-height: 90px;
    --tc-radius: 4px;
    --tc-img: url("https://i.postimg.cc/tJ13CWSJ/LS20260520155053.png");

    /* 🔑 现在 left/top 是金额的"左上角"位置（不是中心点） */
        --tc-amount-left: var(--tc-me-pending-left);
    --tc-amount-top: var(--tc-me-pending-top);
    --tc-amount-size: 17px;
    --tc-amount-weight: 650;
    --tc-amount-color: #ffffff;

    --transfer-amount-text-fill: #ffffff;
    --transfer-amount-text-bg: none;
    --transfer-amount-bg-clip: unset;
    --transfer-amount-text-shadow: none;
}

/* 卡片容器 */
.msg-transfer-card,
.msg-transfer-card.msg-transfer-card {
    background: transparent !important;
    background-image: none !important;
    background-color: transparent !important;
    width: var(--tc-width) !important;
    height: var(--tc-height) !important;
    min-height: 0 !important;
    border-radius: var(--tc-radius) !important;
    padding: 0 !important;
    border: none !important;
    box-shadow: none !important;
    overflow: hidden !important;
    position: relative !important;
    display: block !important;
}

/* 内容容器 */
.msg-transfer-card .msg-transfer-content,
.msg-transfer-card > div {
    position: static !important;
    background: transparent !important;
    padding: 0 !important;
    margin: 0 !important;
    width: auto !important;
    height: auto !important;
}

/* 隐藏除金额之外的所有原生元素 */
.msg-transfer-card .msg-transfer-header,
.msg-transfer-card .msg-transfer-icon,
.msg-transfer-card .msg-transfer-label,
.msg-transfer-card .msg-transfer-subtitle,
.msg-transfer-card .msg-transfer-divider,
.msg-transfer-card .msg-transfer-footer,
.msg-transfer-card .msg-transfer-status-text,
.msg-transfer-card .msg-transfer-chevron,
.msg-transfer-card .msg-transfer-check {
    visibility: hidden !important;
    opacity: 0 !important;
}

/* 图片图层 */
.msg-transfer-card::before {
    content: '' !important;
    position: absolute !important;
    inset: 0 !important;
    background: var(--tc-img) center / 100% 100% no-repeat !important;
    border-radius: var(--tc-radius) !important;
    z-index: 1 !important;
    pointer-events: none !important;
}

/* 💰 金额：左对齐固定，长度变化只往右延伸 */
.msg-transfer-card .msg-transfer-amount {
    position: absolute !important;
    left: var(--tc-amount-left) !important;
    top: var(--tc-amount-top) !important;
    transform: none !important;              /* 🔑 不再居中 */
    text-align: left !important;             /* 🔑 文字左对齐 */
    z-index: 2 !important;

    visibility: visible !important;
    opacity: 1 !important;
    display: block !important;
    width: auto !important;
    height: auto !important;

    background: transparent !important;
    background-image: none !important;
    background-clip: unset !important;
    -webkit-background-clip: unset !important;
    text-shadow: none !important;

    color: var(--tc-amount-color) !important;
    -webkit-text-fill-color: var(--tc-amount-color) !important;

    font-size: var(--tc-amount-size) !important;
    font-weight: var(--tc-amount-weight) !important;
    line-height: 1.2 !important;

    margin: 0 !important;
    padding: 0 !important;
    white-space: nowrap !important;
}

.msg-transfer-card .msg-transfer-amount span,
.msg-transfer-card .msg-transfer-amount * {
    position: static !important;
    transform: none !important;
    left: auto !important;
    top: auto !important;

    visibility: visible !important;
    opacity: 1 !important;
    display: inline !important;

    background: transparent !important;
    background-image: none !important;
    background-clip: unset !important;
    -webkit-background-clip: unset !important;
    text-shadow: none !important;

    color: var(--tc-amount-color) !important;
    -webkit-text-fill-color: var(--tc-amount-color) !important;

    font-size: var(--tc-amount-size) !important;
    font-weight: var(--tc-amount-weight) !important;
    line-height: 1.2 !important;

    margin: 0 !important;
    padding: 0 !important;
    white-space: nowrap !important;
}

/* 外层气泡装饰 */
.bubble-me-custom:has(.msg-transfer-card),
.bubble-them-custom:has(.msg-transfer-card) {
    background: transparent !important;
    padding: 0 !important;
    box-shadow: none !important;
    border: none !important;
}
.bubble-me-custom:has(.msg-transfer-card)::before,
.bubble-them-custom:has(.msg-transfer-card)::before,
.bubble-me-custom:has(.msg-transfer-card)::after,
.bubble-them-custom:has(.msg-transfer-card)::after {
    display: none !important;
}

/* 红点 */
.msg-transfer-card [class*="dot"],
.msg-transfer-card [class*="streaming"],
.msg-transfer-card [class*="indicator"],
.msg-transfer-card [class*="badge"],
.msg-transfer-card [class*="pulse"],
.msg-streaming,
[class*="streaming"] {
    display: none !important;
    visibility: hidden !important;
    opacity: 0 !important;
    width: 0 !important;
    height: 0 !important;
}
/* ================================================
 * 已接收状态：换图 + 金额变橙灰色（最终版）
 * ================================================ */

.msg-transfer-card:has(.msg-transfer-check) {
    --tc-img: url("https://i.postimg.cc/ZqtnNMP6/LS20260519182759.png");
}

/* 隐藏原生的"已被接收"、勾选、"微信转账"等 */
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-header,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-icon,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-label,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-subtitle,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-divider,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-footer,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-status-text,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-chevron,
.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-check {
    visibility: hidden !important;
    opacity: 0 !important;
    display: none !important;
}

/* 🔑 金额：用 html body + 双类名 + 三层选择器 提到最高权重 */
html body .msg-transfer-card.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-amount,
html body .msg-transfer-card.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-amount span,
html body .msg-transfer-card.msg-transfer-card:has(.msg-transfer-check) .msg-transfer-amount * {
    /* 显示 */
    visibility: visible !important;
    opacity: 1 !important;

    /* 颜色：橙灰色，3 个属性一起按死渐变字 */
    color: #BB9366 !important;
    -webkit-text-fill-color: #BB9366 !important;
    background: transparent !important;
    background-image: none !important;
    background-clip: unset !important;
    -webkit-background-clip: unset !important;
    text-shadow: none !important;

    /* 字号字重 */
    font-size: 17px !important;
    font-weight: 650 !important;
    line-height: 1.2 !important;

    z-index: 2 !important;
}

